                (function() {
                    var STORAGE_KEY = 'wl_page_agent_history';
                    var PENDING_TASK_KEY = 'wl_page_agent_pending_task';

                    // === Inject CSS AFTER page-agent loads ===
                    function injectCSS() {
                        if (document.getElementById('wl-pa-style')) return;
                        var style = document.createElement('style');
                        style.id = 'wl-pa-style';
                        style.textContent = `
/* === WL Robot Icon (replace default paper-plane cursor) === */
[class*="cursorBorder_1dgwb_"] {
    background: none !important;
    -webkit-mask: none !important;
    mask: none !important;
    display: none !important;
}
[class*="cursorFilling_1dgwb_"] {
    background: url("data:image/svg+xml,%3csvg%20xmlns='http://www.w3.org/2000/svg'%20viewBox='0%200%20100%20100'%3e%3cdefs%3e%3clinearGradient%20id='wl-rob'%20x1='0%25'%20y1='0%25'%20x2='100%25'%20y2='100%25'%3e%3cstop%20offset='0%25'%20style='stop-color:%23f5c400'/%3e%3cstop%20offset='100%25'%20style='stop-color:%23e6b800'/%3e%3c/linearGradient%3e%3c/defs%3e%3cpath%20d='M50%208%20a4%204%200%201%201%200%208%20a4%204%200%201%201%200-8%20z'%20fill='%23f5c400'/%3e%3crect%20x='48'%20y='16'%20width='4'%20height='10'%20fill='%23f5c400'%20rx='2'/%3e%3crect%20x='20'%20y='28'%20width='60'%20height='46'%20rx='12'%20fill='url(%23wl-rob)'%20stroke='%235a080e'%20stroke-width='2'/%3e%3ccircle%20cx='36'%20cy='46'%20r='5'%20fill='%235a080e'/%3e%3ccircle%20cx='64'%20cy='46'%20r='5'%20fill='%235a080e'/%3e%3crect%20x='38'%20y='60'%20width='24'%20height='4'%20rx='2'%20fill='%235a080e'/%3e%3crect%20x='14'%20y='42'%20width='6'%20height='14'%20rx='3'%20fill='%23f5c400'%20stroke='%235a080e'%20stroke-width='1.5'/%3e%3crect%20x='80'%20y='42'%20width='6'%20height='14'%20rx='3'%20fill='%23f5c400'%20stroke='%235a080e'%20stroke-width='1.5'/%3e%3c/svg%3e") 0 0/100% 100% no-repeat !important;
    transform: none !important;
    margin: 0 !important;
    width: 100% !important;
    height: 100% !important;
    filter: none !important;
}
[class*="cursorRipple_1dgwb_"] {
    display: none !important;
}
[class*="cursor_1dgwb_"] {
    filter: none !important;
}

/* === Remove ALL shadows + blur backdrop === */
[class*="background_1tu05_39"] {
    /* blur backdrop layer — completely hide */
    display: none !important;
}
[class*="doneSuccess_1tu05_366"] {
    box-shadow: none !important;
}
[class*="doneError_1tu05_412"] {
    box-shadow: none !important;
}
[class*="historySectionWrapper_1tu05_246"] {
    box-shadow: none !important;
}
[class*="historySection_1tu05_246"] {
    box-shadow: none !important;
}

/* === Panel background (main container) === */
[class*="background_1tu05_"]:not([class*="background_1tu05_39"]) {
    background: #5a080e !important;
    border-radius: 12px !important;
    box-shadow: none !important;
    border: 1px solid rgba(245,196,0,0.25) !important;
}
[class*="historySectionWrapper_1tu05_"] {
    background: rgba(90,8,14,0.85) !important;
    border: none !important;
}
[class*="header_1tu05_"] {
    background: rgba(90,8,14,0.6) !important;
