}
[class*="statusSection_1tu05_"] {
    display: flex !important; align-items: center !important; gap: 6px !important;
}
[class*="historySection_1tu05_"]::-webkit-scrollbar { width: 4px !important; }
[class*="historySection_1tu05_"]::-webkit-scrollbar-thumb {
    background: rgba(245,196,0,0.3) !important; border-radius: 4px !important;
}

/* === Success / error message cards: keep color but no glow === */
[class*="doneSuccess_1tu05_366"] {
    background: linear-gradient(135deg, #22c55e1a, #22c55e0d) !important;
    border-left: 4px solid #22c55e !important;
}
[class*="doneError_1tu05_412"] {
    background: linear-gradient(135deg, #ef44441a, #ef44440d) !important;
    border-left: 4px solid #ef4444 !important;
}

/* === WL Page Agent Toggle FAB === */
#wl-pa-toggle {
    position: fixed;
    bottom: 20px;
    right: 20px;
    z-index: 2147483640;
    width: 52px;
    height: 52px;
    border-radius: 50%;
    background: linear-gradient(135deg, #5a080e, #7a0c14);
    border: 2px solid #f5c400;
    box-shadow: 0 4px 12px rgba(90,8,14,0.3);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    transition: transform 0.2s, box-shadow 0.2s;
    font-family: Inter, -apple-system, sans-serif;
    -webkit-tap-highlight-color: transparent;
}
#wl-pa-toggle:hover {
    transform: scale(1.08);
    box-shadow: 0 6px 18px rgba(90,8,14,0.4);
}
#wl-pa-toggle:active {
    transform: scale(0.95);
}
#wl-pa-toggle svg {
    width: 32px;
    height: 32px;
    display: block;
}
#wl-pa-toggle .wl-pa-toggle-badge {
    position: absolute;
    top: -4px;
    right: -4px;
    min-width: 18px;
    height: 18px;
    border-radius: 9px;
    background: #22c55e;
    color: #fff;
    font-size: 10px;
    font-weight: 700;
    display: none;
    align-items: center;
    justify-content: center;
    padding: 0 5px;
    border: 2px solid #fff;
    line-height: 1;
}
#wl-pa-toggle .wl-pa-toggle-badge.visible {
    display: flex;
}
#wl-pa-toggle-tooltip {
    position: fixed;
    bottom: 32px;
    right: 84px;
    z-index: 2147483640;
    background: #5a080e;
    color: #f5c400;
    padding: 6px 12px;
    border-radius: 6px;
    font-size: 12px;
    font-weight: 500;
    font-family: Inter, -apple-system, sans-serif;
    box-shadow: 0 2px 8px rgba(0,0,0,0.2);
    border: 1px solid rgba(245,196,0,0.3);
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.2s;
    white-space: nowrap;
}
#wl-pa-toggle-tooltip.visible {
    opacity: 1;
}

/* === Page Agent hidden state === */
body.wl-pa-hidden [class*="wrapper_1tu05_"] {
    display: none !important;
}
body.wl-pa-hidden [class*="cursor_1dgwb_"] {
    display: none !important;
}
/* SimulatorMask: overlay used by agent when clicking — also hide */
body.wl-pa-hidden [class*="SimulatorMask_module_"] {
    display: none !important;
}
                        `;
                        document.head.appendChild(style);
                    }

                    // === Toggle FAB: show/hide Page Agent ===
                    var TOGGLE_KEY = 'wl_page_agent_visible';
                    var paVisible = true; // default visible, will be overridden by storage

                    function getRobotSVG() {
                        // Mini robot icon for the FAB (yellow on transparent, no stroke border needed)
                        return '' +
                            '' +
                            '' +
                            '' +
                            '' +
                            '' +
                            '' +
                            '' +
                            '' +
                            '';
                    }

                    function getCLOSE_SVG() {
                        // X icon when agent is visible (click to hide)
                        return '' +
                            '' +
                            '' +
                            '';
                    }

                    function createToggleFAB() {
                        if (document.getElementById('wl-pa-toggle')) return;

                        var btn = document.createElement('button');
                        btn.id = 'wl-pa-toggle';
                        btn.type = 'button';
                        btn.setAttribute('aria-label', 'Tampilkan/sembunyikan Page Agent');
                        btn.innerHTML = getRobotSVG() + '';

                        var tooltip = document.createElement('div');
                        tooltip.id = 'wl-pa-toggle-tooltip';
                        tooltip.textContent = 'Buka AI Assistant';

                        document.body.appendChild(btn);
                        document.body.appendChild(tooltip);

                        // Restore previous state from storage
                        try {
                            var saved = localStorage.getItem(TOGGLE_KEY);
                            if (saved === 'false') {
                                paVisible = false;
                            } else {
                                paVisible = true; // default visible
                            }
                        } catch(e) {
                            paVisible = true;
                        }
                        applyVisibility(false); // apply without animation on first load

                        // Hover tooltip (desktop)
                        btn.addEventListener('mouseenter', function() {
                            tooltip.classList.add('visible');
                            updateTooltipText();
                        });
                        btn.addEventListener('mouseleave', function() {
                            tooltip.classList.remove('visible');
                        });

                        // Click to toggle
                        btn.addEventListener('click', function(e) {
                            e.preventDefault();
                            e.stopPropagation();
                            paVisible = !paVisible;
                            applyVisibility(true);
                            try { localStorage.setItem(TOGGLE_KEY, paVisible ? 'true' : 'false'); } catch(e) {}
                            console.log('[Page Agent] Toggle: ' + (paVisible ? 'visible' : 'hidden'));
                            updateTooltipText();
                            // Hide tooltip after click on mobile
                            setTimeout(function() { tooltip.classList.remove('visible'); }, 1500);
                        });
                    }

                    function updateTooltipText() {
                        var tooltip = document.getElementById('wl-pa-toggle-tooltip');
                        if (!tooltip) return;
                        tooltip.textContent = paVisible ? 'Sembunyikan AI' : 'Buka AI Assistant';
                    }

                    function updateToggleIcon() {
                        var btn = document.getElementById('wl-pa-toggle');
                        if (!btn) return;
                        // Show robot icon when hidden (suggests "open me")
                        // Show X icon when visible (suggests "close me")
                        var svgHolder = btn;
                        // Preserve badge
                        var badge = document.getElementById('wl-pa-toggle-badge');
                        btn.innerHTML = (paVisible ? getCLOSE_SVG() : getRobotSVG()) +
                            '' + (badge ? badge.textContent : '') + '';
                    }

                    function applyVisibility(animate) {
                        if (paVisible) {
                            document.body.classList.remove('wl-pa-hidden');
                        } else {
                            document.body.classList.add('wl-pa-hidden');
                        }
                        updateToggleIcon();
                    }

                    // Show notification badge when agent completes a task while hidden
                    function showBadgeIfHidden() {
                        if (!paVisible) {
                            var badge = document.getElementById('wl-pa-toggle-badge');
                            if (badge) {
                                badge.classList.add('visible');
                                badge.textContent = '!';
                            }
                        }
                    }
                    function clearBadge() {
                        var badge = document.getElementById('wl-pa-toggle-badge');
                        if (badge) {
                            badge.classList.remove('visible');
                            badge.textContent = '';
                        }
                    }

                    // === Fix Chinese text → Indonesian ===
                    function fixText() {
                        var input = document.querySelector('[class*="_taskInput_1tu05_"]');
                        if (input && input.placeholder && /[\u4e00-\u9fff]/.test(input.placeholder)) {
                            input.placeholder = 'Tulis perintah... (contoh: pesan seblak)';
                        }
                        var wrapper = document.querySelector('[class*="_wrapper_1tu05_"]');
                        if (!wrapper) return;
                        var walker = document.createTreeWalker(wrapper, NodeFilter.SHOW_TEXT, null);
                        var node;
                        while (node = walker.nextNode()) {
                            var t = node.textContent;
                            if (t.indexOf('\u51c6\u5907\u5c31\u7eea') >= 0) node.textContent = node.textContent.replace(/\u51c6\u5907\u5c31\u7eea/g, 'Siap');
                            if (t.indexOf('\u7b49\u5f85\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u7b49\u5f85\u4efb\u52a1[^\n]*/g, 'Menunggu tugas...');
                            if (t.indexOf('\u6b63\u5728\u601d\u8003') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u601d\u8003[^\n]*/g, 'Sedang berpikir...');
                            if (t.indexOf('\u6b63\u5728\u6267\u884c') >= 0) node.textContent = node.textContent.replace(/\u6b63\u5728\u6267\u884c[^\n]*/g, 'Sedang menjalankan...');
                            if (t.indexOf('\u4efb\u52a1\u5b8c\u6210') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5b8c\u6210/g, 'Tugas selesai');
                            if (t.indexOf('\u4efb\u52a1\u5df2\u505c\u6b62') >= 0) node.textContent = node.textContent.replace(/\u4efb\u52a1\u5df2\u505c\u6b62/g, 'Tugas dihentikan');
                            if (t.indexOf('\u51fa\u73b0\u9519\u8bef') >= 0) node.textContent = node.textContent.replace(/\u51fa\u73b0\u9519\u8bef/g, 'Terjadi kesalahan');
                            if (t.indexOf('\u8f93\u5165\u65b0\u4efb\u52a1') >= 0) node.textContent = node.textContent.replace(/\u8f93\u5165\u65b0\u4efb\u52a1[^]*/g, 'Tulis perintah...');
                        }
                    }

                    // === Task state monitoring + persistence ===
                    var agentReady = false;
                    var taskWasActive = false;
                    var savedTaskInstruction = '';

                    function monitorTask(pa) {
                        // Poll task state every 300ms (faster to catch brief states)
                        setInterval(function() {
                            if (!pa || pa.disposed) return;

                            // Detect task state via indicator CSS class + statusText
                            // _thinking_ = actively working
                            // _completed_ = just finished (brief)
                            // no class / _error_ = idle
                            var indicator = document.querySelector('[class*="_indicator_1tu05_"]');
                            var indClass = indicator ? indicator.className : '';
                            var isThinking = indClass.indexOf('_thinking_') >= 0;
                            var isCompleted = indClass.indexOf('_completed_') >= 0;

                            if (isThinking) {
                                // Task is ACTIVE — save instruction
                                if (!taskWasActive) {
                                    taskWasActive = true;
                                    var instruction = pa.task || '';
                                    if (!instruction) {
                                        var input = document.querySelector('[class*="_taskInput_1tu05_\"]');
                                        if (input && input.value) instruction = input.value;
                                    }
                                    savedTaskInstruction = instruction;
                                    try { sessionStorage.setItem(PENDING_TASK_KEY, instruction); } catch(e) {}
                                    console.log('[Page Agent] Task active: ' + instruction.substring(0, 50));
                                }
                            } else if (taskWasActive) {
                                // Was active, now NOT thinking → task ended (completed or stopped)
                                // This catches _completed_ AND idle state (no special class)
                                taskWasActive = false;
                                savedTaskInstruction = '';
                                try { sessionStorage.removeItem(PENDING_TASK_KEY); } catch(e) {}
                                console.log('[Page Agent] Task ended (completed=' + isCompleted + '), cleared pending');
                                // Show badge on FAB if user has hidden Page Agent
                                if (isCompleted) {
                                    showBadgeIfHidden();
                                }
                            }

                            // Always save history
                            if (pa.history && pa.history.length > 0) {
                                try { sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history)); } catch(e) {}
                            }
                        }, 300);
                    }

                    // === Show resume dialog when pending task exists ===
                    function showResumeDialog() {
                        var pending = sessionStorage.getItem(PENDING_TASK_KEY);
                        if (!pending) return;

                        // Immediately clear from storage — we have it in JS variable now
                        sessionStorage.removeItem(PENDING_TASK_KEY);

                        console.log('[Page Agent] Found pending task: ' + pending.substring(0, 50));

                        // Remove any existing dialog
                        var existing = document.getElementById('wl-pa-resume-dialog');
                        if (existing) existing.remove();

                        // Build dialog
                        var overlay = document.createElement('div');
                        overlay.id = 'wl-pa-resume-dialog';
                        overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:999999;display:flex;align-items:center;justify-content:center;font-family:Inter,-apple-system,sans-serif;';

                        var box = document.createElement('div');
                        box.style.cssText = 'background:#fff;border-radius:12px;padding:24px;max-width:400px;width:90%;box-shadow:0 8px 32px rgba(0,0,0,0.2);text-align:center;';

                        var icon = document.createElement('div');
                        icon.innerHTML = '🤖';
                        icon.style.cssText = 'font-size:32px;margin-bottom:12px;';

                        var title = document.createElement('h3');
                        title.textContent = 'Lanjutkan tugas?';
                        title.style.cssText = 'color:#5a080e;font-size:18px;font-weight:600;margin:0 0 8px 0;';

                        var desc = document.createElement('p');
                        desc.innerHTML = 'Ada tugas yang belum selesai:
' + pending.substring(0, 60) + (pending.length > 60 ? '...' : '') + '';
                        desc.style.cssText = 'color:#666;font-size:14px;line-height:22px;margin:0 0 20px 0;';

                        var btnRow = document.createElement('div');
                        btnRow.style.cssText = 'display:flex;gap:12px;justify-content:center;';

                        var btnDone = document.createElement('button');
                        btnDone.textContent = 'Sudah selesai';
                        btnDone.style.cssText = 'flex:1;padding:10px 16px;border:1px solid #ddd;background:#fff;color:#666;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer;font-family:Inter,-apple-system,sans-serif;transition:all 0.2s;';
                        btnDone.onmouseenter = function() { this.style.background = '#f5f5f5'; };
                        btnDone.onmouseleave = function() { this.style.background = '#fff'; };

                        var btnResume = document.createElement('button');
                        btnResume.textContent = 'Lanjut';
                        btnResume.style.cssText = 'flex:1;padding:10px 16px;border:none;background:#f5c400;color:#5a080e;border-radius:8px;font-size:14px;font-weight:600;cursor:pointer;font-family:Inter,-apple-system,sans-serif;transition:all 0.2s;';
                        btnResume.onmouseenter = function() { this.style.background = '#e6b800'; };
                        btnResume.onmouseleave = function() { this.style.background = '#f5c400'; };

                        btnDone.onclick = function() {
                            sessionStorage.removeItem(PENDING_TASK_KEY);
                            overlay.remove();
                            console.log('[Page Agent] User chose: Sudah selesai. Pending cleared.');
                        };

                        btnResume.onclick = function() {
                            overlay.remove();
                            // Auto-show Page Agent if user had hidden it
                            if (!paVisible) {
                                paVisible = true;
                                applyVisibility(true);
                                try { localStorage.setItem(TOGGLE_KEY, 'true'); } catch(e) {}
                                clearBadge();
                            }
                            // 'pending' is captured in closure
                            setTimeout(function() {
                                var currentPa = window.pageAgent;
                                if (!currentPa || currentPa.disposed) {
                                    console.log('[Page Agent] Agent not available');
                                    return;
                                }

                                // Save old history before execute() clears it
                                var oldHistory = [];
                                try {
                                    var stored = sessionStorage.getItem(STORAGE_KEY);
                                    if (stored) oldHistory = JSON.parse(stored) || [];
                                } catch(e) {}

                                // Build context summary from old history
                                var contextSummary = '';
                                if (oldHistory.length > 0) {
                                    var actions = oldHistory.map(function(h) {
                                        if (h.reflection && h.reflection.evaluation_previous_goal) {
                                            return h.reflection.evaluation_previous_goal;
                                        }
                                        if (h.type === 'output' && h.text) {
                                            return h.text;
                                        }
                                        return '';
                                    }).filter(function(s) { return s && s.length > 10; });
                                    if (actions.length > 0) {
                                        contextSummary = 'Konteks sebelumnya: ' + actions.join('. ') + '. ';
                                    }
                                }

                                var fullTask = contextSummary + pending;
                                console.log('[Page Agent] Resuming with context: ' + fullTask.substring(0, 80));

                                // Monkey-patch: temporarily override execute to preserve history
                                var origExecute = currentPa.execute.bind(currentPa);
                                currentPa.execute = async function(task) {
                                    // Call original (which clears history internally)
                                    var result = await origExecute(task);
                                    // After completion, merge old history back
                                    try {
                                        var newHistory = this.history || [];
                                        this.history = oldHistory.concat(newHistory);
                                        // Trigger history change event so UI updates
                                        this.dispatchEvent(new Event('historychange'));
                                        // Save merged history
                                        sessionStorage.setItem(STORAGE_KEY, JSON.stringify(this.history));
                                    } catch(e) {
                                        console.log('[Page Agent] History merge error: ' + e.message);
                                    }
                                    return result;
                                };

                                // Execute with context-enriched task
                                currentPa.execute(fullTask).then(function() {
                                    console.log('[Page Agent] Resume completed');
                                    // Restore original execute
                                    currentPa.execute = origExecute;
                                }).catch(function(e) {
                                    console.log('[Page Agent] Resume failed: ' + (e.message || e));
                                    // Restore history on failure
                                    try {
                                        currentPa.history = oldHistory;
                                        currentPa.dispatchEvent(new Event('historychange'));
                                    } catch(e2) {}
                                    // Restore original execute
                                    currentPa.execute = origExecute;
                                });
                            }, 500);
                        };

                        btnRow.appendChild(btnDone);
                        btnRow.appendChild(btnResume);
                        box.appendChild(icon);
                        box.appendChild(title);
                        box.appendChild(desc);
                        box.appendChild(btnRow);
                        overlay.appendChild(box);
                        document.body.appendChild(overlay);

                        console.log('[Page Agent] Resume dialog shown');
                    }

                    // === Main setup ===
                    function setupAgent() {
                        var pa = window.pageAgent;
                        if (!pa || pa.disposed) return false;

                        // 1. Set language
                        try {
                            pa.config.language = 'id-ID';
                            if (pa.config.pageController && pa.config.pageController.config) {
                                pa.config.pageController.config.language = 'id-ID';
                            }
                        } catch(e) {}

                        // 1b. Enhance ask_user tool description — make agent prefer asking over guessing
                        try {
                            if (pa.tools && pa.tools.has && pa.tools.has('ask_user')) {
                                var askTool = pa.tools.get('ask_user');
                                askTool.description = 'Ask the user a question and wait for their answer. ' +
                                    'ALWAYS use this tool before filling forms with personal information ' +
                                    '(name, email, phone, address, password). ' +
                                    'NEVER guess or use placeholder/test values like "test@test.com" or "John Doe". ' +
                                    'If you encounter a form that requires user details, ask the user first.';
                            }
                        } catch(e) {
                            console.log('[Page Agent] Could not enhance ask_user: ' + e.message);
                        }

                        // 1c. Intercept form fills on /shop/address — block dummy data
                        var formInterceptorInterval = setInterval(function() {
                            if (window.location.pathname.indexOf('/shop/address') < 0) return;
                            // Override input values that look like test data
                            var inputs = document.querySelectorAll('form input[name], form textarea[name], form select[name]');
                            inputs.forEach(function(input) {
                                if (input.dataset._wl_monitored) return;
                                input.dataset._wl_monitored = 'true';
                                // Watch for programmatic value changes
                                var origSetter = Object.getOwnPropertyDescriptor(
                                    input.tagName === 'TEXTAREA' ? HTMLTextAreaElement.prototype :
                                    input.tagName === 'SELECT' ? HTMLSelectElement.prototype :
                                    HTMLInputElement.prototype, 'value'
                                ).set;
                                Object.defineProperty(input, 'value', {
                                    get: function() { return origGetter.call(this); },
                                    set: function(val) {
                                        // Block common test/dummy values
                                        var lowerVal = (val || '').toLowerCase().trim();
                                        var dummyPatterns = ['test', 'dummy', 'john doe', 'jane doe',
                                            'test@test', 'example.com', '123456', 'aaa', 'xxx',
                                            'foo@', 'bar@', 'asdf', 'qwerty'];
                                        var isDummy = dummyPatterns.some(function(p) {
                                            return lowerVal.indexOf(p) >= 0;
                                        });
                                        if (isDummy && input.name !== 'csrf_token') {
                                            console.log('[Page Agent] Blocked dummy value for ' + input.name + ': ' + val);
                                            // Show ask prompt to user instead
                                            var pa2 = window.pageAgent;
                                            if (pa2 && pa2.onAskUser) {
                                                pa2.onAskUser('Form ' + input.name + ' membutuhkan data asli Anda. Silakan isi sendiri:').then(function(answer) {
                                                    if (answer) origSetter.call(input, answer);
                                                });
                                            }
                                            return; // Block the dummy value
                                        }
                                        origSetter.call(this, val);
                                    }
                                });
                                var origGetter = Object.getOwnPropertyDescriptor(
                                    input.tagName === 'TEXTAREA' ? HTMLTextAreaElement.prototype :
                                    input.tagName === 'SELECT' ? HTMLSelectElement.prototype :
                                    HTMLInputElement.prototype, 'value'
                                ).get;
                            });
                        }, 1000);
                        // Stop interceptor after 60s
                        setTimeout(function() { clearInterval(formInterceptorInterval); }, 60000);

                        // 2. Restore chat history
                        try {
                            var saved = sessionStorage.getItem(STORAGE_KEY);
                            if (saved) {
                                var h = JSON.parse(saved);
                                if (Array.isArray(h) && h.length > 0) pa.history = h;
                            }
                        } catch(e) {}

                        // 3. Start task monitor (delayed to skip demo init _thinking_ state)
                        setTimeout(function() {
                            monitorTask(pa);
                        }, 3000);

                        // 4. Save everything before page unload
                        window.addEventListener('beforeunload', function() {
                            try {
                                if (pa.task && pa.task !== '') {
                                    sessionStorage.setItem(PENDING_TASK_KEY, pa.task);
                                }
                                if (pa.history && pa.history.length > 0) {
                                    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pa.history));
                                }
                            } catch(e) {}
                        });

                        // 5. Show resume dialog if there's a pending task
                        setTimeout(function() {
                            showResumeDialog();
                        }, 2000);

                        return true;
                    }

                    // === Init loop ===
                    var attempts = 0;
                    var interval = setInterval(function() {
                        attempts++;
                        injectCSS();
                        fixText();
                        createToggleFAB(); // create FAB as soon as body is ready
                        if (window.pageAgent && !window.pageAgent.disposed) {
                            if (!agentReady) {
                                if (setupAgent()) {
                                    agentReady = true;
                                    console.log('[Page Agent] Warung Lakku AI ready (styled, Indonesian, auto-resume enabled)');
                                }
                            }
                        }
                        if (attempts >= 120) clearInterval(interval);
                    }, 500);

                    // MutationObserver: fix text on DOM changes
                    var observer = new MutationObserver(function() {
                        fixText();
                    });
                    if (document.body) {
                        observer.observe(document.body, { childList: true, subtree: true, characterData: true });
                    }

                    // When user opens the panel via FAB, clear the notification badge
                    document.addEventListener('click', function(e) {
                        if (e.target && e.target.closest && e.target.closest('#wl-pa-toggle') && paVisible) {
                            clearBadge();
                        }
                    }, true);
                })();
